"use strict";const path=require("node:path"),{VFile:VFile}=require("../linter/vfile.js");class ProcessorService{preprocessSync(e,r){const{processor:s}=r;let o;try{o=s.preprocess(e.rawBody,e.path)}catch(e){return{ok:!1,errors:[{ruleId:null,fatal:!0,severity:2,message:`Preprocessing error: ${e.message.replace(/^line \d+:/iu,"").trim()}`,line:e.lineNumber,column:e.column}]}}if("function"==typeof o.then)throw new Error("Unsupported: Preprocessor returned a promise.");return{ok:!0,files:o.map((r,s)=>{if("string"==typeof r)return r;const o=path.join(e.path,`${s}_${r.filename}`);return new VFile(o,r.text,{physicalPath:e.physicalPath})})}}postprocessSync(e,r,s){const{processor:o}=s;return o.postprocess(r,e.path)}}module.exports={ProcessorService:ProcessorService};